optimized_federated_query:
# Smart Federated Query with UNION for Multiple Class Interpretations
# Each UNION branch uses different endpoints or predicates

SELECT ?director ?film ?genre ?x
WHERE {
  # Scenario 1: ?x=Concept, ?film=Feature
  {
    SERVICE <http://localhost:8897/sparql/> {
      ?x <http://www.w3.org/2002/07/owl#sameAs> ?film . # ?x:Concept, ?film:Feature
      ?film <http://dbpedia.org/ontology/director> ?director .
      ?x <http://data.linkedmdb.org/resource/movie/genre> ?genre .
    }
    # Unknown endpoint (no metadata)
      ?director <http://dbpedia.org/ontology/nationality> <http://dbpedia.org/resource/Italy> .
  }

  UNION

  # Scenario 2: ?x=Drug, ?film=Drug
  {
    SERVICE <http://localhost:8895/sparql/> {
      ?x <http://www.w3.org/2002/07/owl#sameAs> ?film . # ?x:Drug, ?film:Drug
      ?film <http://dbpedia.org/ontology/director> ?director .
      ?x <http://data.linkedmdb.org/resource/movie/genre> ?genre .
    }
    # Unknown endpoint (no metadata)
      ?director <http://dbpedia.org/ontology/nationality> <http://dbpedia.org/resource/Italy> .
  }
}
LIMIT 1000
